import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import { CartProvider } from './context/CartContext';

// Importación de tus componentes corregidos
import Login from './components/Login';
import PanelCliente from './components/PanelCliente';
import DashboardVendedor from './components/Dashboard';
import Registro from './components/Registro';

// Componente para proteger rutas
const PrivateRoute = ({ children, roleRequired }) => {
    const { user, isAuthenticated, loading } = useAuth();

    if (loading) return <div>Cargando sesión...</div>;
    if (!isAuthenticated) return <Navigate to="/login" />;

    // Si la ruta requiere un rol específico (vendedor/cliente)
    if (roleRequired && user.rol !== roleRequired) {
        return <Navigate to="/" />;
    }

    return children;
};

const AppRoutes = () => {
    const { user, isAuthenticated } = useAuth();

    return (
        <Routes>
            <Route path="/login" element={!isAuthenticated ? <Login /> : <Navigate to="/" />} />
            <Route path="/registro" element={<Registro />} />

            {/* Ruta Raíz: Redirige según el rol */}
            <Route path="/" element={
                <PrivateRoute>
                    {user?.rol === 'vendedor' ? <DashboardVendedor /> : <PanelCliente />}
                </PrivateRoute>
            } />

            {/* Rutas específicas si fueran necesarias */}
            <Route path="/tienda" element={
                <PrivateRoute roleRequired="cliente">
                    <PanelCliente />
                </PrivateRoute>
            } />

            {/* Fallback */}
            <Route path="*" element={<Navigate to="/" />} />
        </Routes>
    );
};

function App() {
    return (
        <AuthProvider>
            <CartProvider>
                <Router>
                    <AppRoutes />
                </Router>
            </CartProvider>
        </AuthProvider>
    );
}

export default App;
